import java.util.*;
import java.util.stream.*;

public class Main {

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        Map<String, Integer> counts = new TreeMap<>();
        while (input.hasNext()) counts.merge(input.next(), 1, Integer::sum);
        System.out.println(counts.entrySet().stream().map(entry -> entry.getKey() + "=" + entry.getValue()).collect(Collectors.joining(" ")));
    }
}
